const data = JSON.parse(fs.readFileSync('d:/ClaudeWorkspace/08_客户跟进/Okki/data/tm_conversations_latest.json', 'utf8'));
console.log('Total conversations:', data.total);
console.log('');
const convs = data.conversations;

// Our uid
const OUR_UID = '2500000853693@icbu';

// Filter out system messages
function isSystemMessage(content) {
  const patterns = [
    '自动接待将不再触发', 'Since you have read the conversation',
    'Marco大模型翻译', '阿里国际Marco大模型翻译',
    '买家有流失风险', 'Buyer has churn risk',
    '一旦离开平台发生纠纷或欺诈',
    '由于您介入该会话', 'Due to your intervention',
    'AI给您生成了一条回复建议',
    'You have a visitor', 'Follow up with them',
    'This buyer has been pre-screened', 'has a clear request',
    'is available to assign it to you', 'is not within your service scope',
    '买家已确认签收',
    '当前会话已自动关闭', 'conversation has been closed',
    '这个客户当前有被分配', 'is currently assigned',
    '订单已发货', '订单发货提醒',
    '反馈'
  ];
  if (!content) return true;
  const c = String(content).trim();
  if (!c) return true;
  for (const p of patterns) {
    if (c.includes(p)) return true;
  }
  return false;
}

function isAutoReply(content) {
  if (!content) return false;
  const c = String(content);
  return c.includes('自动接待') || c.includes('automatic reception') || c.includes('auto reply');
}

// For each conversation, extract key info
const results = [];
for (const conv of convs) {
  const lastTime = new Date(conv.lastContactTimeLong).getTime();
  const now = new Date('2026-05-08T18:49:00+08:00').getTime();
  const daysAgo = Math.floor((now - lastTime) / (1000 * 60 * 60 * 24));

  results.push({
    cid: conv.cid,
    name: conv.name || 'Unknown',
    country: conv.complianceCountryCode || 'N/A',
    lastContact: new Date(conv.lastContactTimeLong).toISOString().slice(0,10),
    daysAgo: daysAgo,
    unread: conv.unreadCount || 0,
    latestMsgType: conv.latestMessage?.messageType || 'unknown',
    latestMsgContent: (conv.latestMessage?.content || '').substring(0, 100),
    tags: conv.tagInfo || [],
    loginId: conv.loginId || '',
    aliId: conv.aliId || 0,
    accountId: conv.accountId || 0
  });
}

// Output as JSON for further processing
console.log(JSON.stringify(results, null, 2));
