const fs = require('fs');
const path = require('path');

// Read metadata
const meta = JSON.parse(fs.readFileSync('d:/ClaudeWorkspace/08_客户跟进/Okki/data/tm_conversations_latest.json', 'utf8'));
const chatDir = 'd:/ClaudeWorkspace/08_客户跟进/Okki/data/chat_history/';

// Build cid -> file lookup
const files = fs.readdirSync(chatDir).filter(f => f.endsWith('.json'));
console.error('Chat history files:', files.length);

// Read each chat file and count messages
const msgCounts = {};
for (const f of files) {
  try {
    const content = fs.readFileSync(path.join(chatDir, f), 'utf8');
    const data = JSON.parse(content);
    // Handle both array and object formats
    const msgs = Array.isArray(data) ? data : (data.messages || data.conversation || []);
    const cidFromFile = f.replace('.json', '').replace(/_/g, '#').replace(/^([0-9]+)-([0-9]+)_([0-9]+)_([a-z]+)$/, '\$1-\$2#\$3@\$4');

    // The filename format is: aliId-ourId_11011_icbu.json
    // The cid format is: aliId-ourId#11011@icbu
    const parts = f.replace('.json', '').split('_');
    const cid = parts[0] + '#' + parts[1] + '@' + parts[2];
    msgCounts[cid] = msgs.length;
  } catch(e) {
    console.error('Error reading:', f, e.message);
  }
}

// Now build results
const results = [];
for (const conv of meta.conversations) {
  const lastTime = new Date(conv.lastContactTimeLong).getTime();
  const now = Date.now();
  const daysAgo = Math.floor((now - lastTime) / (1000 * 60 * 60 * 24));

  const msgCount = msgCounts[conv.cid] || 0;

  results.push({
    cid: conv.cid,
    name: conv.name || 'Unknown',
    country: conv.complianceCountryCode || 'N/A',
    lastContact: new Date(conv.lastContactTimeLong).toISOString().slice(0,10),
    daysAgo: daysAgo,
    unread: conv.unreadCount || 0,
    latestMsgType: conv.latestMessage?.messageType || 'unknown',
    latestMsgContent: (conv.latestMessage?.content || '').substring(0, 120),
    msgCount: msgCount
  });
}

// Output as JSON
console.log(JSON.stringify(results));
" 2>&1

