const fs = require('fs');
const path = require('path');

// Read metadata
const meta = JSON.parse(fs.readFileSync('d:/ClaudeWorkspace/08_客户跟进/Okki/data/tm_conversations_latest.json', 'utf8'));
const chatDir = 'd:/ClaudeWorkspace/08_客户跟进/Okki/data/chat_history/';

// System message patterns
function isSystemMessage(content) {
  if (!content || !String(content).trim()) return true;
  const c = String(content);
  const patterns = [
    '自动接待将不再触发', 'Since you have read the conversation',
    'Marco大模型翻译', '阿里国际Marco大模型翻译',
    '买家有流失风险', 'Buyer has churn risk',
    '一旦离开平台发生纠纷或欺诈',
    '由于您介入该会话', 'Due to your intervention',
    'AI给您生成了一条回复建议',
    'You have a visitor', 'Follow up with them',
    'This buyer has been pre-screened', 'has a clear request',
    'is available to assign it to you', 'is not within your service scope',
    '买家已确认签收', '订单已发货', '订单发货提醒',
    '反馈', '当前会话已自动关闭', 'conversation has been closed',
    '这个客户当前有被分配', 'is currently assigned',
    'auto reply', 'automatic reception'
  ];
  for (const p of patterns) {
    if (c.includes(p)) return true;
  }
  return false;
}

// Signal keywords
const buySignals = ['place order','make order','order','commander','acheter','下单','pedido','comprare','send me','I need','I want','how much','price','sample','échantillon','muestra','catalogue','catalog','company profile','address','delivery','shipping','freight','PI','invoice','payment','deposit','production','MOQ'];
const highSignals = ['how much','price','sample','catalogue','address','quantity','size','color','design','logo','custom','OEM','brand','shipping to'];

// Build cid -> file mapping
const files = fs.readdirSync(chatDir).filter(f => f.endsWith('.json'));
const cidToFile = {};
for (const f of files) {
  const parts = f.replace('.json', '').split('_');
  const cid = parts[0] + '#' + parts[1] + '@' + parts[2];
  cidToFile[cid] = f;
}

// Count messages
const msgCounts = {};
for (const [cid, f] of Object.entries(cidToFile)) {
  try {
    const data = JSON.parse(fs.readFileSync(path.join(chatDir, f), 'utf8'));
    const msgs = Array.isArray(data) ? data : (data.messages || data.conversation || []);
    msgCounts[cid] = msgs;
  } catch(e) { msgCounts[cid] = []; }
}

const OUR_UID = '2500000853693@icbu';
const results = [];

for (const conv of meta.conversations) {
  const msgs = msgCounts[conv.cid] || [];
  const msgCount = msgs.length;

  // Count client messages and our messages
  let clientMsgs = 0, ourMsgs = 0, sysMsgs = 0;
  let lastRealMsg = null, lastClientMsg = null, lastOurMsg = null;

  for (let i = msgs.length - 1; i >= 0; i--) {
    const m = msgs[i];
    const content = m.message?.content?.text?.content || m.content || '';
    const sender = m.message?.sender?.uid || m.sender || '';

    if (isSystemMessage(content)) {
      sysMsgs++;
      continue;
    }

    const isOurs = sender === OUR_UID || sender.includes('2500000853693');
    if (isOurs) {
      ourMsgs++;
      if (!lastOurMsg) lastOurMsg = { content, time: m.message?.gmtCreate || m.time };
    } else {
      clientMsgs++;
      if (!lastClientMsg) lastClientMsg = { content, time: m.message?.gmtCreate || m.time, sender };
    }
    if (!lastRealMsg) lastRealMsg = { content, time: m.message?.gmtCreate || m.time, isOurs, sender };
  }

  const lastTime = new Date(conv.lastContactTimeLong).getTime();
  const now = Date.now();
  const daysAgo = Math.floor((now - lastTime) / (1000 * 60 * 60 * 24));

  // Score signals
  let signals = [];
  let totalSignalScore = 0;
  for (const m of msgs) {
    const content = String(m.message?.content?.text?.content || m.content || '').toLowerCase();
    for (const s of buySignals) {
      if (content.includes(s)) { signals.push(s); totalSignalScore++; break; }
    }
  }

  results.push({
    cid: conv.cid,
    name: conv.name || 'Unknown',
    country: conv.complianceCountryCode || 'N/A',
    lastContact: new Date(conv.lastContactTimeLong).toISOString().slice(0,10),
    daysAgo,
    unread: conv.unreadCount || 0,
    latestMsgType: conv.latestMessage?.messageType || 'unknown',
    latestMsgContent: (conv.latestMessage?.content || '').substring(0, 80),
    msgCount,
    clientMsgs,
    ourMsgs,
    lastClientContent: lastClientMsg?.content?.substring(0, 80) || '',
    lastOurContent: lastOurMsg?.content?.substring(0, 80) || '',
    hasClientReply: clientMsgs > 0 && lastClientMsg !== null,
  });
}

// Classification function
function classify(r) {
  // P0: Immediate action - PI pending, active negotiation, client recently replied
  const hasRecentClientReply = r.hasClientReply && r.daysAgo <= 7;
  const isActive = r.msgCount >= 10 && r.daysAgo <= 3;
  const isHighMsg = r.clientMsgs >= 5 && r.daysAgo <= 7;

  if (r.daysAgo <= 3 && r.clientMsgs >= 3 && r.lastClientContent) return 'P0';
  if (r.daysAgo <= 1 && r.msgCount >= 5 && r.hasClientReply) return 'P0';
  if (r.daysAgo <= 7 && r.clientMsgs >= 10) return 'P0';

  // P1: This week follow-up - active within 7-14 days
  if (r.daysAgo <= 14 && r.clientMsgs >= 3) return 'P1';
  if (r.daysAgo <= 7 && r.msgCount >= 5) return 'P1';
  if (r.daysAgo <= 14 && r.msgCount >= 20) return 'P1';

  // P2: Observe - within 7-30 days, some interaction
  if (r.daysAgo <= 30 && r.msgCount >= 5) return 'P2';

  // P3: Low activity - 8-90 days
  if (r.daysAgo <= 90 && r.msgCount >= 3) return 'P3';

  // P4: Silent
  return 'P4';
}

for (const r of results) {
  r.tier = classify(r);
}

// Sort by tier then by daysAgo
const tierOrder = {P0:0, P1:1, P2:2, P3:3, P4:4};
results.sort((a,b) => tierOrder[a.tier] - tierOrder[b.tier] || a.daysAgo - b.daysAgo);

// Output
const tiers = {P0:[], P1:[], P2:[], P3:[], P4:[]};
for (const r of results) {
  tiers[r.tier].push(r);
}

console.log('=== S1: 五梯队分类 ===');
console.log('');
for (const t of ['P0','P1','P2','P3','P4']) {
  console.log('## ' + t + ' (' + tiers[t].length + '人)');
  if (t === 'P0' || t === 'P1') {
    tiers[t].forEach((r,i) => {
      const reason = [];
      if (r.clientMsgs >= 5) reason.push('客户活跃('+r.clientMsgs+'条客户消息)');
      if (r.daysAgo <= 3) reason.push(r.daysAgo+'天前联系');
      if (r.msgCount >= 50) reason.push('长对话('+r.msgCount+'条)');
      console.log((i+1) + '. ' + r.name + ' | ' + r.country + ' | ' + r.msgCount + '条 | ' + r.daysAgo + '天前 | ' + (reason.join(', ') || '近期互动'));
    });
  }
  console.log('');
}

// Summary
console.log('=== 总计 ===');
console.log('P0: ' + tiers.P0.length + ' | P1: ' + tiers.P1.length + ' | P2: ' + tiers.P2.length + ' | P3: ' + tiers.P3.length + ' | P4: ' + tiers.P4.length);
console.log('全部: ' + results.length + '人');
" 2>&1

