const fs = require('fs');
const meta = JSON.parse(fs.readFileSync('d:/ClaudeWorkspace/08_客户跟进/Okki/data/tm_conversations_latest.json', 'utf8'));
const conv = meta.conversations.find(c => (c.name || '').toLowerCase().includes('abigail'));
if (conv) {
  console.log('Name:', conv.name);
  console.log('Country:', conv.complianceCountryCode);
  console.log('CID:', conv.cid);
  console.log('LastContact:', new Date(conv.lastContactTimeLong).toISOString());
  const cidParts = conv.cid.replace('#', '_').replace('@', '_');
  console.log('File:', cidParts + '.json');
} else {
  console.log('NOT FOUND in metadata');
  // Search more broadly
  const all = meta.conversations.filter(c => (c.name || '').toLowerCase().includes('mutuku') || (c.name || '').toLowerCase().includes('abi'));
